function updateGoogleDriveBackupButtonState(isSignedIn,isConfigured=false){const backupButton=document.getElementById('googleDriveBackupButton'),restoreButton=document.getElementById('googleDriveRestoreButton');if(backupButton)backupButton.disabled=!isSignedIn||!!googleDriveBackupInProgress;if(restoreButton)restoreButton.disabled=!isConfigured}function setText(id,value){const el=document.getElementById(id);if(el)el.textContent=value}function setGoogleState(label,isConnected=false){const el=document.getElementById('googleState');if(!el)return;el.innerHTML=`<span class="googlePlugIcon ${isConnected?'connected':'disconnected'}" aria-hidden="true"></span><span>${label}</span>`}function swScriptLabel(worker){return worker?.scriptURL||'—'}
