function renderOcrDiagnosticDashboard(){if(!window.OcrDiagnosticService)return;if(window.TicketArchiveService&&db.settings?.retentionMode)TicketArchiveService.setRetentionMode(db.settings.retentionMode);else OcrDiagnosticService.purge();const stats=OcrDiagnosticService.stats(),tickets=stats.tickets||{count:0,totalBytes:0,averageBytes:0};const enabled=document.getElementById('ocrDiagnosticEnabled');if(enabled)enabled.checked=isOcrDiagnosticEnabled();setText('ocrDiagnosticCount',String(stats.diagnostics?.count??stats.count));setText('ocrTicketCount',String(tickets.count));setText('ocrTicketSize',formatBytes(tickets.totalBytes,'mo'));setText('ocrDiagnosticSize',formatBytes(stats.diagnostics?.totalBytes??stats.totalBytes,'mo'));setText('ocrDiagnosticAverage',`${formatBytes(tickets.averageBytes,'ko')} / ticket`);setText('ocrArchiveTotalSize',formatBytes(stats.totalBytes,'mo'));setText('ocrDiagnosticOldest',stats.oldest?formatDateTime(stats.oldest):'—');setText('ocrDiagnosticNewest',stats.newest?formatDateTime(stats.newest):'—');setText('ocrArchiveOldest',(stats.tickets?.oldest||stats.diagnostics?.oldest)?formatDateTime([stats.tickets?.oldest,stats.diagnostics?.oldest].filter(Boolean).sort()[0]):'—');setText('ocrArchiveNewest',(stats.tickets?.newest||stats.diagnostics?.newest)?formatDateTime([stats.tickets?.newest,stats.diagnostics?.newest].filter(Boolean).sort().at(-1)):'—');setText('ocrArchiveRetention',retentionLabel(db.settings?.retentionMode||'manual'));setText('ocrArchiveEstimate500',formatBytes((tickets.averageBytes||350000)*500,'mo'));setText('ocrArchiveEstimate1000',formatBytes((tickets.averageBytes||350000)*1000,'mo'));document.querySelectorAll('input[name=ocrRetention]').forEach(input=>{input.checked=input.value===(db.settings?.retentionMode||'manual')})}
